	@Test
	void probeReusesChildHandlesAcrossFullAndPartialScans() throws IOException {
		Object idSpace = new Object();
		ProbeSource left = new ProbeSource(idSpace, 10, false);
		ProbeSource right = new ProbeSource(idSpace, 20, false);
		NativeLmdbQuerySource source = CompositeNativeLmdbQuerySource.combine(List.of(left, right));

		NativeLmdbQuerySource.NativeProbe probe = source.newProbe();
		RecordIterator retainedIterator;
		try {
			try (RecordIterator first = probe.open(1, 2, 3, 4)) {
				retainedIterator = first;
				assertThat(first.next()[1]).isEqualTo(10);
				assertThat(first.next()[1]).isEqualTo(20);
				assertThat(first.next()).isNull();
			}
			try (RecordIterator partial = probe.open(5, 6, 7, 8)) {
				assertThat(partial)
						.as("the composite wrapper is reusable until its retained probe closes")
						.isSameAs(retainedIterator);
				assertThat(partial.next()[1]).isEqualTo(10);
			}
			try (RecordIterator third = probe.open(9, 10, 11, 12)) {
				assertThat(third).isSameAs(retainedIterator);
				assertThat(third.next()[1]).isEqualTo(10);
				assertThat(third.next()[1]).isEqualTo(20);
				assertThat(third.next()).isNull();
			}
		} finally {
			probe.close();
		}

		assertThat(left.probeCreations).isEqualTo(1);
		assertThat(right.probeCreations).isEqualTo(1);
		assertThat(left.probeOpens).isEqualTo(3);
		assertThat(right.probeOpens).isEqualTo(2);
		assertThat(left.probeCloses).isEqualTo(1);
		assertThat(right.probeCloses).isEqualTo(1);
		assertThat(left.iteratorCloses).isEqualTo(3);
		assertThat(right.iteratorCloses).isEqualTo(2);
		assertThat(left.statementOpens).isZero();
		assertThat(right.statementOpens).isZero();
	}

