	@Test
	void parallelSourcesUseActiveSnapshotAndCloseEveryOwnedChildExactlyOnce() throws IOException {
		Object idSpace = new Object();
		IllegalStateException firstFailure = new IllegalStateException("synthetic first parallel close failure");
		IllegalStateException secondFailure = new IllegalStateException("synthetic second parallel close failure");
		CloseTrackingParallelSource first = new CloseTrackingParallelSource(idSpace, firstFailure);
		CloseTrackingParallelSource second = new CloseTrackingParallelSource(idSpace, secondFailure);
		CloseTrackingParallelSource last = new CloseTrackingParallelSource(idSpace, null);
		ParallelOpeningSource firstParent = ParallelOpeningSource.active(idSpace, first);
		ParallelOpeningSource inactive = ParallelOpeningSource.inactive(idSpace);
		ParallelOpeningSource secondParent = ParallelOpeningSource.active(idSpace, second);
		ParallelOpeningSource lastParent = ParallelOpeningSource.active(idSpace, last);
		NativeLmdbQuerySource source = CompositeNativeLmdbQuerySource.combine(
				List.of(firstParent, inactive, secondParent, lastParent));

		NativeLmdbQuerySource.ParallelSource[] opened = source.openParallelSources(1);

		assertThat(firstParent.parallelOpenCalls).isOne();
		assertThat(inactive.parallelOpenCalls).isZero();
		assertThat(secondParent.parallelOpenCalls).isOne();
		assertThat(lastParent.parallelOpenCalls).isOne();
		assertThat(opened).hasSize(1);
		assertThatThrownBy(opened[0]::close)
				.isSameAs(firstFailure)
				.satisfies(failure -> assertThat(failure.getSuppressed()).containsExactly(secondFailure));
		assertParallelSourcesClosedExactlyOnce(first, second, last);

		opened[0].close();
		assertParallelSourcesClosedExactlyOnce(first, second, last);
	}

	@Test
	void parallelCompositeCloseIsExactOnceUnderConcurrentCancellation() throws Exception {
		int attempts = 20_000;
		Object idSpace = new Object();
		AtomicReference<ParallelSource> current = new AtomicReference<>();
		AtomicBoolean duplicateClose = new AtomicBoolean();
		Phaser phases = new Phaser(3);
		Runnable closer = () -> {
			for (int i = 0; i < attempts; i++) {
				phases.arriveAndAwaitAdvance();
				current.get().close();
				phases.arriveAndAwaitAdvance();
			}
		};
		Thread firstCloser = Thread.ofPlatform().name("composite-close-1").start(closer);
		Thread secondCloser = Thread.ofPlatform().name("composite-close-2").start(closer);

		for (int i = 0; i < attempts; i++) {
			ConcurrentCloseTrackingParallelSource first = new ConcurrentCloseTrackingParallelSource(idSpace);
			ConcurrentCloseTrackingParallelSource second = new ConcurrentCloseTrackingParallelSource(idSpace);
			NativeLmdbQuerySource source = CompositeNativeLmdbQuerySource.combine(List.of(
					ParallelOpeningSource.active(idSpace, first),
					ParallelOpeningSource.active(idSpace, second)));
			current.set(source.openParallelSources(1)[0]);
			phases.arriveAndAwaitAdvance();
			phases.arriveAndAwaitAdvance();
			if (first.closeInvocations.get() != 1 || second.closeInvocations.get() != 1) {
				duplicateClose.set(true);
			}
		}
		firstCloser.join();
		secondCloser.join();

		assertThat(duplicateClose)
				.as("concurrent cancellation must transfer each retained child's close ownership exactly once")
				.isFalse();
	}

	@Test
	void parallelOpenRejectsMixedSnapshotEpochAndClosesEveryChild() throws IOException {
		Object idSpace = new Object();
		SnapshotEpoch epoch = new SnapshotEpoch();
		SnapshotOpeningSource first = new SnapshotOpeningSource(idSpace, epoch, true);
		SnapshotOpeningSource second = new SnapshotOpeningSource(idSpace, epoch, false);
		NativeLmdbQuerySource source = CompositeNativeLmdbQuerySource.combine(List.of(first, second));

		ParallelSource[] opened = source.openParallelSources(3);
		if (opened != null) {
			for (ParallelSource parallelSource : opened) {
				parallelSource.close();
			}
		}

		assertThat(first.parallelOpenCalls).isOne();
		assertThat(second.parallelOpenCalls).isOne();
		assertThat(first.children)
				.extracting(SnapshotParallelSource::snapshotId)
				.containsOnly(1L);
		assertThat(second.children)
				.extracting(SnapshotParallelSource::snapshotId)
				.containsOnly(2L);
		assertSnapshotChildrenClosedExactlyOnce(first, second);
		assertThat(opened)
				.as("a composite must refuse parallel siblings captured from different committed snapshots")
				.isNull();
	}

