	@Test
	void parallelOpenFailurePreservesPrimaryAndClosesEveryOpenedSibling() {
		Object idSpace = new Object();
		IOException openFailure = new IOException("synthetic parallel open failure");
		IllegalStateException firstCloseFailure = new IllegalStateException(
				"synthetic first partial-open close failure");
		IllegalStateException secondCloseFailure = new IllegalStateException(
				"synthetic second partial-open close failure");
		CloseTrackingParallelSource first = new CloseTrackingParallelSource(idSpace, firstCloseFailure);
		CloseTrackingParallelSource second = new CloseTrackingParallelSource(idSpace, secondCloseFailure);
		CloseTrackingParallelSource last = new CloseTrackingParallelSource(idSpace, null);
		ParallelOpeningSource opened = ParallelOpeningSource.active(idSpace, first, second, last);
		ParallelOpeningSource failing = ParallelOpeningSource.failing(idSpace, openFailure);
		NativeLmdbQuerySource source = CompositeNativeLmdbQuerySource.combine(List.of(opened, failing));

		assertThatThrownBy(() -> source.openParallelSources(3))
				.isSameAs(openFailure)
				.satisfies(failure -> assertThat(failure.getSuppressed())
						.containsExactly(firstCloseFailure, secondCloseFailure));

		assertThat(opened.parallelOpenCalls).isOne();
		assertThat(failing.parallelOpenCalls).isOne();
		assertParallelSourcesClosedExactlyOnce(first, second, last);
	}

	@Test
	void orderedOpenAndReadFailuresPreservePrimaryAndCloseEveryIterator() {
		assertOrderedOpenFailurePreservesPrimary();
		assertOrderedReadFailurePreservesPrimary();
	}

	private static void assertOrderedOpenFailurePreservesPrimary() {
		Object idSpace = new Object();
		IOException openFailure = new IOException("synthetic ordered open failure");
		IllegalStateException firstCloseFailure = new IllegalStateException(
				"synthetic first ordered-open close failure");
		IllegalStateException secondCloseFailure = new IllegalStateException(
				"synthetic second ordered-open close failure");
		OrderedCleanupSource first = OrderedCleanupSource.rows(idSpace, 10, null, firstCloseFailure);
		OrderedCleanupSource second = OrderedCleanupSource.rows(idSpace, 20, null, secondCloseFailure);
		OrderedCleanupSource failing = OrderedCleanupSource.failingOpen(idSpace, openFailure);
		NativeLmdbQuerySource source = CompositeNativeLmdbQuerySource.combine(List.of(first, second, failing));

		assertThatThrownBy(() -> source.statements(StatementOrder.O, -1, -1, -1, -1))
				.isSameAs(openFailure)
				.satisfies(failure -> assertThat(failure.getSuppressed())
						.containsExactly(firstCloseFailure, secondCloseFailure));
		assertOrderedIteratorsClosedExactlyOnce(first, second);
		assertThat(failing.orderedOpenCalls).isOne();
	}

