	private static void assertParallelSourcesClosedExactlyOnce(CloseTrackingParallelSource... sources) {
		for (CloseTrackingParallelSource source : sources) {
			assertThat(source.closeInvocations).isOne();
			assertThat(source.physicalCloses).isOne();
		}
	}

	private static void assertSnapshotChildrenClosedExactlyOnce(SnapshotOpeningSource... sources) {
		for (SnapshotOpeningSource source : sources) {
			assertThat(source.children).hasSize(3);
			for (SnapshotParallelSource child : source.children) {
				assertThat(child.closeInvocations).isOne();
				assertThat(child.physicalCloses).isOne();
			}
		}
	}

	private static void assertOrderedIteratorsClosedExactlyOnce(OrderedCleanupSource... sources) {
		for (OrderedCleanupSource source : sources) {
			assertThat(source.iterator).isNotNull();
			assertThat(source.iterator.closeInvocations).isOne();
			assertThat(source.iterator.physicalCloses).isOne();
		}
	}

	private static void assertRetainedProbesClosedExactlyOnce(ProbeSource... sources) {
		for (ProbeSource source : sources) {
			assertThat(source.probeCreations).isEqualTo(1);
			assertThat(source.probeCloseCalls).isEqualTo(1);
			assertThat(source.probeCloses).isEqualTo(1);
		}
	}

	private static final class OrderedSource implements NativeLmdbQuerySource, ParallelSource {
		final Object idSpace;
		final String index;
		final long[][] rows;
		int seekCalls;

		OrderedSource(Object idSpace, String index, long[][] rows) {
			this.idSpace = idSpace;
			this.index = index;
			this.rows = rows;
		}

		@Override
		public long idOf(Value value) {
			throw new UnsupportedOperationException();
		}

		@Override
		public Value lazyValue(long id) {
			throw new UnsupportedOperationException();
		}

		@Override
		public Object idSpace() {
			return idSpace;
		}

		@Override
		public RecordIterator statements(long subj, long pred, long obj, long context) {
			return iterator();
		}

		@Override
		public RecordIterator statements(StatementOrder order, long subj, long pred, long obj, long context) {
			return iterator();
		}

		@Override
		public String indexName(long subj, long pred, long obj, long context) {
			return index;
		}

		@Override
		public String indexName(StatementOrder order, long subj, long pred, long obj, long context) {
			return index;
		}

		private RecordIterator iterator() {
			return new RecordIterator() {
				int index;

				@Override
				public long[] next() {
					return index < rows.length ? rows[index++] : null;
				}

				@Override
				public String getIndexName() {
					return OrderedSource.this.index;
				}

				@Override
				public boolean seekForward(long subj, long pred, long obj, long context) {
					seekCalls++;
					while (index < rows.length && compare(rows[index], subj, pred, obj, context) < 0) {
						index++;
					}
					return true;
				}

				@Override
				public void close() {
				}
			};
		}

		private int compare(long[] row, long subj, long pred, long obj, long context) {
			for (int i = 0; i < index.length(); i++) {
				int component = switch (index.charAt(i)) {
				case 's' -> 0;
				case 'p' -> 1;
				case 'o' -> 2;
				case 'c' -> 3;
				default -> throw new AssertionError("unsupported test index " + index);
				};
				long target = switch (component) {
				case 0 -> subj;
				case 1 -> pred;
				case 2 -> obj;
				case 3 -> context;
				default -> throw new AssertionError(component);
				};
				int comparison = Long.compareUnsigned(row[component], target);
				if (comparison != 0) {
					return comparison;
				}
			}
			return 0;
		}

		@Override
		public long count(long subj, long pred, long obj, long context) {
			return rows.length;
		}

		@Override
		public boolean has(long subj, long pred, long obj, long context) {
			return rows.length > 0;
		}

		@Override
		public double estimate(long subj, long pred, long obj, long context) {
			return rows.length;
		}

		@Override
		public boolean hasStatementsInSource() {
			return true;
		}

		@Override
		public void close() {
		}
	}

